using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, CourseCode = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, CourseCode = "CS201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and competitive programming. He previously worked at Google Research.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, CourseCode = "CS310", Title = "Database Systems", Description = "Design and implementation of relational databases. Covers SQL, normalization, indexing, and transaction processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Rodriguez", InstructorBio = "Dr. Rodriguez is a database researcher with expertise in distributed systems. She contributed to PostgreSQL development.", IsFeatured = false },
            new() { Id = 4, DepartmentId = 1, CourseCode = "CS420", Title = "Machine Learning", Description = "Introduction to machine learning algorithms including regression, classification, clustering, and neural networks.", Credits = 4, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Alex Kim", InstructorBio = "Dr. Kim holds a PhD in AI from Stanford and has published over 50 papers in top ML conferences.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, CourseCode = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Taylor", InstructorBio = "Dr. Taylor has taught calculus for over 20 years and authored two widely-used textbooks.", IsFeatured = false },
            new() { Id = 6, DepartmentId = 2, CourseCode = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson is a mathematician specializing in applied linear algebra and numerical methods.", IsFeatured = true },
            new() { Id = 7, DepartmentId = 2, CourseCode = "MATH301", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM", InstructorName = "Dr. Robert Taylor", InstructorBio = "Dr. Taylor has taught calculus for over 20 years and authored two widely-used textbooks.", IsFeatured = false },
            new() { Id = 8, DepartmentId = 3, CourseCode = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Michael Brown", InstructorBio = "Dr. Brown is an experimental physicist who previously worked at CERN on particle detection systems.", IsFeatured = false },
            new() { Id = 9, DepartmentId = 3, CourseCode = "PHYS201", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:20 PM + Lab Fri 1:00–3:00 PM", InstructorName = "Dr. Lisa Zhang", InstructorBio = "Dr. Zhang is an expert in electromagnetic theory and photonics with numerous patents.", IsFeatured = true },
            new() { Id = 10, DepartmentId = 4, CourseCode = "ENG101", Title = "College Writing", Description = "Develop critical thinking and writing skills through essay composition, peer review, and revision.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. David Miller", InstructorBio = "Prof. Miller is a published author and writing coach with an MFA from the Iowa Writers' Workshop.", IsFeatured = false },
            new() { Id = 11, DepartmentId = 4, CourseCode = "ENG220", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present, including major movements and authors.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", InstructorName = "Dr. Karen White", InstructorBio = "Dr. White specializes in 20th-century American fiction and has published three books on the subject.", IsFeatured = false },
            new() { Id = 12, DepartmentId = 5, CourseCode = "HIST101", Title = "World History to 1500", Description = "Survey of world civilizations from prehistory through the Renaissance, covering major cultures and events.", Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", InstructorName = "Dr. Thomas Green", InstructorBio = "Dr. Green is a historian of ancient civilizations with fieldwork experience in Egypt and Mesopotamia.", IsFeatured = false },
            new() { Id = 13, DepartmentId = 5, CourseCode = "HIST250", Title = "Modern European History", Description = "Europe from the Enlightenment to the present: revolutions, world wars, and the formation of the EU.", Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM", InstructorName = "Dr. Anna Schmidt", InstructorBio = "Dr. Schmidt studied at Oxford and specializes in 20th-century European political history.", IsFeatured = true },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public string GetDepartmentName(int departmentId) =>
        _departments.FirstOrDefault(d => d.Id == departmentId)?.Name ?? "Unknown";
}

