@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@rendermode InteractiveServer
@inject CatalogService Catalog
@inject NavigationManager Navigation

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="SearchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in Catalog.GetDepartments())
            {
                <option value="@dept.Id">@dept.Code — @dept.Name</option>
            }
        </select>
    </div>
</div>

@{
    var results = Catalog.SearchCourses(SearchTerm, SelectedDepartmentId);
}

<p class="text-muted">Showing @results.Count course(s)</p>

<table class="table table-striped table-hover">
    <thead>
        <tr>
            <th>Code</th>
            <th>Title</th>
            <th>Department</th>
            <th>Credits</th>
            <th>Instructor</th>
            <th></th>
        </tr>
    </thead>
    <tbody>
        @foreach (var course in results)
        {
            <tr>
                <td>@course.CourseCode</td>
                <td>@course.Title</td>
                <td>@Catalog.GetDepartmentName(course.DepartmentId)</td>
                <td>@course.Credits</td>
                <td>@course.InstructorName</td>
                <td><a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
            </tr>
        }
    </tbody>
</table>

@code {
    private string? SearchTerm { get; set; }
    private int SelectedDepartmentId { get; set; }

    protected override void OnInitialized()
    {
        var uri = new Uri(Navigation.Uri);
        var query = System.Web.HttpUtility.ParseQueryString(uri.Query);
        if (int.TryParse(query["departmentId"], out var deptId))
        {
            SelectedDepartmentId = deptId;
        }
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-secondary">Back to Courses</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="courses?departmentId=@course.DepartmentId">@Catalog.GetDepartmentName(course.DepartmentId)</a></li>
            <li class="breadcrumb-item active">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4>Instructor</h4>
            <p><strong>@course.InstructorName</strong></p>
            <p>@course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Info</h5>
                    <ul class="list-unstyled">
                        <li><strong>Credits:</strong> @course.Credits</li>
                        <li class="mt-2"><strong>Schedule:</strong> @course.Schedule</li>
                        <li class="mt-2"><strong>Department:</strong> @Catalog.GetDepartmentName(course.DepartmentId)</li>
                    </ul>
                    <a href="enroll?courseId=@course.Id" class="btn btn-success w-100 mt-3">Enroll in This Course</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog
@inject NavigationManager Navigation

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course. You will receive a confirmation from the registrar's office.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@Catalog.GetCourse(Model.CourseId)?.Title</strong> has been received.</p>
        <p>The registrar's office will process your request and notify you via your student email.</p>
        <a href="enroll" class="btn btn-primary">Submit Another Request</a>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="EnrollmentForm">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
            <ValidationMessage For="() => Model.StudentName" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g., CS123456" />
            <ValidationMessage For="() => Model.StudentId" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                <option value="0">— Select a course —</option>
                @foreach (var course in Catalog.GetCourses())
                {
                    <option value="@course.Id">@course.CourseCode — @course.Title (@course.Credits cr)</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    private bool Submitted { get; set; }

    protected override void OnInitialized()
    {
        var uri = new Uri(Navigation.Uri);
        var query = System.Web.HttpUtility.ParseQueryString(uri.Query);
        if (int.TryParse(query["courseId"], out var courseId) && Model.CourseId == 0)
        {
            Model.CourseId = courseId;
        }
    }

    private void HandleSubmit()
    {
        Submitted = true;
    }
}

